    private boolean validateFileSize(Uri uri, long maxSize) {
        try {
            android.database.Cursor cursor = getContentResolver().query(uri,
                    new String[]{android.provider.OpenableColumns.SIZE}, null, null, null);
            if (cursor != null) {
                try {
                    if (cursor.moveToFirst()) {
                        int sizeIndex = cursor.getColumnIndex(android.provider.OpenableColumns.SIZE);
                        if (sizeIndex >= 0 && !cursor.isNull(sizeIndex)) {
                            long fileSize = cursor.getLong(sizeIndex);
                            if (fileSize > maxSize) {
                                Log.w(TAG, "File size " + fileSize + " exceeds maximum " + maxSize);
                                return false;
                            }
                            if (fileSize <= 0) {
                                Log.w(TAG, "File size is zero or negative");
                                return false;
                            }
                        }
                    }
                } finally {
                    cursor.close();
                }
            }
        } catch (Exception e) {
            Log.w(TAG, "Could not determine file size, proceeding with caution", e);
            // If we can't determine size, we'll rely on other safeguards (sample size, etc.)
        }
        return true;
    }

